<script>
export default {
  methods: {
    toggleCollapse(id) {
      console.log(`Toggling collapse of element: ${id}`);
      const element = document.getElementById(id);
      const classes = `${element.classList}`.split(" ");
      console.log(`Element's classes: ${classes}`);
      console.log(`Contains show?: ${classes.includes("show")}`);
      if (classes.includes("show")) {
        element.classList.remove("show");
      } else {
        element.classList.add("show");
      }
    },
  },
};
